
BEGIN;

-- category

-- supplier

-- warehouse

-- product (235 registros)

-- stock_movement (4000 registros generados aleatoriamente)
SELECT
    CASE WHEN random() < 0.5 THEN 'IN' ELSE 'OUT' END,
    (floor(random() * 100) + 1)::int,
    timestamp '2025-01-01 00:00:00' + (random() * 730) * interval '1 day',
    prod.id,
    wh.id
FROM generate_series(1, 4000) AS movement
CROSS JOIN LATERAL (SELECT id FROM product   ORDER BY random() LIMIT 1) AS prod
CROSS JOIN LATERAL (SELECT id FROM warehouse ORDER BY random() LIMIT 1) AS wh;

COMMIT;